arguments.command:
cd /tmp && mkdir -p binlog-reader && cd binlog-reader && cat > binlog-reader.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.415" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'CEOF'
using System;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD ERRORS ===");
build.VisitAllChildren<Error>(error => {
    Console.WriteLine($"[ERROR] Project={error.GetNearestParent<Project>()?.Name ?? "?"} Code={error.Code} File={error.File}({error.LineNumber},{error.ColumnNumber}): {error.Text}");
});

Console.WriteLine("\n=== BUILD WARNINGS ===");
build.VisitAllChildren<Warning>(warning => {
    Console.WriteLine($"[WARN] Project={warning.GetNearestParent<Project>()?.Name ?? "?"} Code={warning.Code} File={warning.File}({warning.LineNumber},{warning.ColumnNumber}): {warning.Text}");
});

Console.WriteLine($"\nBuild succeeded: {build.Succeeded}");

Console.WriteLine("\n=== PROJECT RESULTS ===");
build.VisitAllChildren<Project>(project => {
    Console.WriteLine($"  Project: {project.Name} Succeeded={project.Succeeded}");
});
CEOF
