using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get the source files from the archive
var archive = build.SourceFilesArchive;
if (archive != null)
{
    Console.WriteLine($"Archive type: {archive.GetType().FullName}");
    Console.WriteLine($"Archive length: {archive.Length}");
}
else
{
    Console.WriteLine("No archive.");
}

// Try SourceFiles property  
Console.WriteLine("\n=== Searching all nodes for source content ===");
build.VisitAllChildren<SourceFile>(sf => {
    Console.WriteLine($"SourceFile: Name={sf.Name}, SourceFilePath={sf.SourceFilePath}");
    // Try to get children
    if (sf.HasChildren)
    {
        foreach(var c in sf.Children)
            Console.WriteLine($"  Child: {c.GetType().Name}: {c}");
    }
});

// Try to find UserService.cs content from the CscCommandLineArgs or Csc task
Console.WriteLine("\n=== CSC TASK ARGS ===");
build.VisitAllChildren<Task>(task => {
