        var project = task.GetNearestParent<Project>();
        if (project?.Name?.Contains("Services") == true)
        {
            Console.WriteLine($"Csc in {project.Name}");
            foreach (var child in task.Children)
            {
                if (child is Property prop)
                    Console.WriteLine($"  Property: {prop.Name} = {prop.Value?.Substring(0, Math.Min(prop.Value.Length, 300))}");
                else if (child is Parameter param)
                {
                    Console.WriteLine($"  Parameter: {param.Name}");
                    foreach (var item in param.Children.OfType<Item>().Take(20))
                        Console.WriteLine($"    Item: {item.Text}");
                }
                else if (child is Message msg)
                    Console.WriteLine($"  Message: {msg.Text?.Substring(0, Math.Min(msg.Text?.Length ?? 0, 200))}");
            }
        }
    }
});
