using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);
var archive = build.SourceFilesArchive;
using var ms = new MemoryStream(archive);
using var zip = new ZipArchive(ms, ZipArchiveMode.Read);

// Read project.assets.json for Services
var servicesAssets = zip.Entries.FirstOrDefault(e => e.FullName.Contains("Services") && e.FullName.EndsWith("project.assets.json"));
if (servicesAssets != null)
{
    Console.WriteLine("=== Services/obj/project.assets.json ===");
    using var reader = new StreamReader(servicesAssets.Open());
    Console.WriteLine(reader.ReadToEnd());
}

// Also dump Csc task parameters for Services
Console.WriteLine("\n=== CSC TASK PARAMETERS FOR Services.csproj ===");
build.VisitAllChildren<Task>(task => {
    if (task.Name == "Csc")
    {
        var project = task.GetNearestParent<Project>();
        if (project?.Name?.Contains("Services") == true)
        {
            Console.WriteLine($"Csc in {project.Name}");
            foreach (var child in task.Children)
            {
                if (child is Property prop)
                    Console.WriteLine($"  Property: {prop.Name} = {prop.Value?.Substring(0, Math.Min(prop.Value.Length, 300))}");
                else if (child is Parameter param)
                {
                    Console.WriteLine($"  Parameter: {param.Name}");
                    foreach (var item in param.Children.OfType<Item>().Take(20))
                        Console.WriteLine($"    Item: {item.Text}");
                }
                else if (child is Message msg)
                    Console.WriteLine($"  Message: {msg.Text?.Substring(0, Math.Min(msg.Text?.Length ?? 0, 200))}");
            }
        }
    }
});
